     1→import { useState, useEffect, useMemo } from 'react';
     2→import { Play, Pause, Square, Plus, Clock, Target, TrendingUp, Calendar, RotateCcw } from 'lucide-react';
     3→import { useTimeTrackingStore } from '../stores/useTimeTrackingStore';
     4→import { useTimeTrackingPanelStore } from '../stores/useTimeTrackingPanelStore';
     5→import { formatDuration, formatTime } from '../utils/timeFormatters';
     6→import { ProjectSelector } from './ProjectSelector';
     7→import { ManualTimeEntryModal } from './ManualTimeEntryModal';
     8→import { IdlePrompt } from './IdlePrompt';
     9→import { useIdleDetection, getIdleDetectionSettings } from '../hooks/useIdleDetection';
    10→import type { TimeEntry, DailySummary } from '../types';
    11→
    12→/**
    13→ * TimeTrackingTimer Component
    14→ * Full-featured time tracking interface for the Schedule page
    15→ * Mirrors sidebar functionality with enhanced Toggl-like features:
    16→ * - Active timer with start/pause/stop
    17→ * - Manual entry option
    18→ * - Recent entries (continue functionality)
    19→ * - Daily/weekly statistics
    20→ * - Goal tracking (future)
    21→ */
    22→export function TimeTrackingTimer() {
    23→  // Time tracking state from store
    24→  const {
    25→    activeEntry,
    26→    entries,
    27→    projects,
    28→    startTimer,
    29→    stopTimer,
    30→    pauseTimer,
    31→    resumeTimer,
    32→    updateTimerDescription,
    33→    updateActiveEntry,
    34→    continueEntry,
    35→    getRecentEntries,
    36→    getTodayTotal,
    37→    getWeeklySummary,
    38→    isTimerRunning,
    39→    timerDescription,
    40→    timerProjectId,
    41→  } = useTimeTrackingStore();
    42→
    43→  // Panel settings (shared with sidebar)
    44→  const { timeFormat, showSeconds } = useTimeTrackingPanelStore();
    45→
    46→  // Computed values from getters
    47→  const isRunning = isTimerRunning();
    48→  const currentDescription = timerDescription();
    49→  const currentProjectId = timerProjectId();
    50→
    51→  // Local state
    52→  const [currentTime, setCurrentTime] = useState<number>(0);
    53→  const [description, setDescription] = useState(currentDescription || '');
    54→  const [selectedProjectId, setSelectedProjectId] = useState<string | null>(currentProjectId || null);
    55→  const [isBillable, setIsBillable] = useState(() => {
    56→    // Load billable default from localStorage (default: true for freelance use)
    57→    const saved = localStorage.getItem('timeTracking:billableDefault');
    58→    return saved !== null ? saved === 'true' : true;
    59→  });
    60→  const [showManualEntryModal, setShowManualEntryModal] = useState(false);
    61→  const [recentEntries, setRecentEntries] = useState<TimeEntry[]>([]);
    62→  const [todayTotal, setTodayTotal] = useState<number>(0);
    63→  const [weeklySummary, setWeeklySummary] = useState<{ totalDuration: number; dailyBreakdown: DailySummary[] } | null>(null);
    64→
    65→  // Idle detection state
    66→  const [idleSettings] = useState(() => getIdleDetectionSettings());
    67→  const [showIdlePrompt, setShowIdlePrompt] = useState(false);
    68→  const [idleStartTime, setIdleStartTime] = useState<string | null>(null);
    69→  const [idleDuration, setIdleDuration] = useState(0);
    70→
    71→  // Idle detection hook (only active when timer is running and enabled)
    72→  useIdleDetection({
    73→    threshold: idleSettings.thresholdMinutes * 60 * 1000,
    74→    enabled: idleSettings.enabled && isRunning,
    75→    onIdle: () => {
    76→      // Record when idle started
    77→      setIdleStartTime(new Date().toISOString());
    78→    },
    79→    onReturn: (idleTime) => {
    80→      // Show idle prompt when user returns
    81→      setIdleDuration(idleTime);
    82→      setShowIdlePrompt(true);
    83→    }
    84→  });
    85→
    86→  // Update timer every second when running
    87→  useEffect(() => {
    88→    if (!activeEntry?.startTime) {
    89→      setCurrentTime(0);
    90→      return;
    91→    }
    92→
    93→    const updateTime = () => {
    94→      const start = new Date(activeEntry.startTime!).getTime();
    95→      const now = Date.now();
    96→      const elapsed = Math.floor((now - start) / 1000);
    97→      setCurrentTime(elapsed);
    98→    };
    99→
   100→    updateTime();
   101→
   102→    if (isRunning) {
   103→      const interval = setInterval(updateTime, 1000);
   104→      return () => clearInterval(interval);
   105→    }
   106→  }, [isRunning, activeEntry]);
   107→
   108→  // Load data on mount and when entries change
   109→  useEffect(() => {
   110→    const loadData = async () => {
   111→      const recent = await getRecentEntries(48);
   112→      setRecentEntries(recent.slice(0, 10));
   113→
   114→      const total = await getTodayTotal();
   115→      setTodayTotal(total);
   116→
   117→      const weekly = await getWeeklySummary();
   118→      setWeeklySummary(weekly);
   119→    };
   120→
   121→    loadData();
   122→    const interval = setInterval(loadData, 60000);
   123→    return () => clearInterval(interval);
   124→  }, [entries, getRecentEntries, getTodayTotal, getWeeklySummary]);
   125→
   126→  // Sync description with active entry
   127→  useEffect(() => {
   128→    setDescription(currentDescription || '');
   129→  }, [currentDescription]);
   130→
   131→  // Sync project with active entry
   132→  useEffect(() => {
   133→    setSelectedProjectId(currentProjectId || null);
   134→  }, [currentProjectId]);
   135→
   136→  // Handlers
   137→  const handleStartTimer = () => {
   138→    // Save billable preference for next time
   139→    localStorage.setItem('timeTracking:billableDefault', String(isBillable));
   140→
   141→    startTimer({
   142→      description: description || 'Untitled Task',
   143→      projectId: selectedProjectId || undefined,
   144→      billable: isBillable,
   145→    });
   146→  };
   147→
   148→  const handleBillableChange = (billable: boolean) => {
   149→    setIsBillable(billable);
   150→    // Save immediately so it persists across page refreshes
   151→    localStorage.setItem('timeTracking:billableDefault', String(billable));
   152→  };
   153→
   154→  const handleStopTimer = async () => {
   155→    await stopTimer();
   156→    setDescription('');
   157→    setSelectedProjectId(null);
   158→  };
   159→
   160→  const handleDescriptionChange = (e: React.ChangeEvent<HTMLInputElement>) => {
   161→    const newDescription = e.target.value;
   162→    setDescription(newDescription);
   163→    if (isRunning || activeEntry) {
   164→      updateTimerDescription(newDescription);
   165→    }
   166→  };
   167→
   168→  const handleProjectChange = (projectId: string | null) => {
   169→    setSelectedProjectId(projectId);
   170→    if (activeEntry) {
   171→      updateActiveEntry({ projectId: projectId || undefined });
   172→    }
   173→  };
   174→
   175→  const handleContinueEntry = (entry: TimeEntry) => {
   176→    continueEntry(entry.id);
   177→  };
   178→
   179→  // Get project by ID
   180→  const getProject = (projectId: string | null | undefined) => {
   181→    if (!projectId) return null;
   182→    return projects.find(p => p.id === projectId);
   183→  };
   184→
   185→  // Calculate weekly average
   186→  const weeklyAverage = useMemo(() => {
   187→    if (!weeklySummary) return 0;
   188→    const daysWithEntries = weeklySummary.dailyBreakdown.filter(d => d.totalDuration > 0).length;
   189→    return daysWithEntries > 0 ? weeklySummary.totalDuration / daysWithEntries : 0;
   190→  }, [weeklySummary]);
   191→
   192→  // Idle prompt handlers
   193→  const handleIdleKeep = () => {
   194→    // Continue tracking (no action needed)
   195→    setShowIdlePrompt(false);
   196→    setIdleStartTime(null);
   197→  };
   198→
   199→  const handleIdleDiscard = async () => {
   200→    // Stop timer at idle start time
   201→    if (!activeEntry || !idleStartTime) return;
   202→
   203→    await stopTimer();
   204→
   205→    // The timer has been stopped at the idle start time
   206→    setShowIdlePrompt(false);
   207→    setIdleStartTime(null);
   208→  };
   209→
   210→  const handleIdleAdjust = async (adjustedEndTime: string) => {
   211→    // Stop timer at adjusted time
   212→    if (!activeEntry || !adjustedEndTime) return;
   213→
   214→    await stopTimer();
   215→
   216→    setShowIdlePrompt(false);
   217→    setIdleStartTime(null);
   218→  };
   219→
   220→  const handleIdleDismiss = () => {
   221→    // User will decide later (keep timer running)
   222→    setShowIdlePrompt(false);
   223→  };
   224→
   225→  return (
   226→    <div className="space-y-6">
   227→      {/* Main Timer Card */}
   228→      <div className="bg-surface-light dark:bg-surface-dark-elevated rounded-lg border border-border-light dark:border-border-dark p-6">
   229→        <div className="flex flex-col lg:flex-row gap-6">
   230→          {/* Timer Section */}
