    23→
    24→/**
    25→ * TimeEntryCalendar Component (UNIFIED)
    26→ * Full calendar view showing time entries AND calendar events
    27→ * Supports 4 view modes: Monthly, Weekly, Daily, Agenda/List
    28→ * Migrated all functionality from Planning Calendar Widget
    29→ */
    30→export function TimeEntryCalendar({ onEditEntry, onCreateEvent, onEditEvent }: TimeEntryCalendarProps) {
    31→  const { entries, projects, loadEntries, loadProjects } = useTimeTrackingStore();
    32→  const { events, importEvents } = useCalendarStore();
    33→  const { tasks } = useKanbanStore();
    34→
    35→  const [loading, setLoading] = useState(true);
    36→  const [currentDate, setCurrentDate] = useState(new Date());
    37→  const [viewMode, setViewMode] = useState<ViewMode>('monthly');
    38→  const [importStatus, setImportStatus] = useState<{ message: string; type: 'success' | 'error' } | null>(null);
    39→  const [dayDetailModal, setDayDetailModal] = useState<{ dateKey: string; events: CalendarEvent[]; tasks: Task[]; timeEntries: TimeEntry[]; totalDuration: number } | null>(null);
    40→
    41→  // Group tasks by their due date (convert ISO date to standard date key)
    42→  const tasksByDate = useMemo(() => {
    43→    const result: Record<string, Task[]> = {};
