    45→      if (task.dueDate && task.status !== 'done') {
    46→        // Convert YYYY-MM-DD to YYYY-M-D standard format
    47→        const [year, month, day] = task.dueDate.split('-').map(Number);
    48→        const dateKey = `${year}-${month}-${day}`;
    49→        if (!result[dateKey]) result[dateKey] = [];
    50→        result[dateKey].push(task);
