      return new Date(year, month, 1).toLocaleDateString('en-US', {
        month: 'long',
        year: 'numeric'
      });
    } else if (viewMode === 'weekly') {
      const startOfWeek = new Date(currentDate);
      startOfWeek.setDate(startOfWeek.getDate() - startOfWeek.getDay());
