  const handleDayClick = (dateKey: string) => {
    // Click on a day opens the DayDetailModal
    const dayEvents = expandedEvents[dateKey] || [];
    const dayTasks = tasksByDate[dateKey] || [];

    // Get time entries for this day (need to convert dateKey to ISO format)
    const [year, month, day] = dateKey.split('-').map(Number);
    const isoDateStr = `${year}-${month.toString().padStart(2, '0')}-${day.toString().padStart(2, '0')}`;
    const dayEntries = entriesByDate.get(isoDateStr) || [];
    const totalDuration = dayEntries.reduce((sum, entry) => sum + entry.duration, 0);

    // If no content, go straight to create event modal
    if (dayEvents.length === 0 && dayTasks.length === 0 && dayEntries.length === 0) {
      if (onCreateEvent) {
        onCreateEvent(dateKey);
      }
    } else {
      // Show modal with all events, tasks, and time entries for this day
      setDayDetailModal({ dateKey, events: dayEvents, tasks: dayTasks, timeEntries: dayEntries, totalDuration });
    }
  };

  const handleEventClick = (event: CalendarEvent, dateKey: string) => {
    if (onEditEvent) {
      onEditEvent(event, dateKey);
    }
  };

  return (
    <div className="space-y-6">
      {/* Navigation Header - Using shared CalendarHeader component */}
      <CalendarHeader
        displayText={getDisplayText()}
        onPrevious={handlePrevious}
        onNext={handleNext}
        onToday={handleToday}
        showNavigation={viewMode !== 'agenda'}
        viewMode={viewMode}
        onViewModeChange={setViewMode}
        onCreate={onCreateEvent ? () => onCreateEvent(getStandardDateKey(new Date())) : undefined}
        createButtonText="New Event"
        onPrint={handlePrint}
        onExport={handleExport}
        onImport={handleImport}
        statusMessage={importStatus && (
          <span className={`text-xs px-2 py-1 rounded ${
            importStatus.type === 'success'
              ? 'bg-status-success/20 text-status-success'
              : 'bg-status-error/20 text-status-error'
          }`}>
            {importStatus.message}
          </span>
        )}
      />

      {/* View Content */}
      {viewMode === 'monthly' ? (
        /* Monthly View - Using shared MonthlyCalendarGrid component */
        <MonthlyCalendarGrid
          year={year}
          month={month}
          onDayClick={handleDayClick}
          renderDayContent={({ dateKey, isoDateKey }) => {
            const dayEntries = entriesByDate.get(isoDateKey) || [];
            const dayEvents = expandedEvents[dateKey] || [];
            const dayTasks = tasksByDate[dateKey] || [];
            const totalDuration = dayEntries.reduce((sum, entry) => sum + entry.duration, 0);
            const hasContent = dayEntries.length > 0 || dayEvents.length > 0 || dayTasks.length > 0;

            if (!hasContent) {
              return (
                <div className="text-[10px] text-text-light-tertiary dark:text-text-dark-tertiary opacity-0 group-hover:opacity-100">
                  Click to add
                </div>
              );
            }

            return (
              <div className="space-y-1">
                {/* Time Tracked */}
                {totalDuration > 0 && (
                  <div className="flex items-center gap-1 text-xs text-accent-magenta dark:text-accent-cyan font-medium">
                    <Clock className="w-3 h-3" />
                    {formatDuration(totalDuration, { showSeconds: false })}
                  </div>
                )}

                {/* Entry Count */}
                {dayEntries.length > 0 && (
                  <div className="text-[10px] text-text-light-tertiary dark:text-text-dark-tertiary">
                    {dayEntries.length} {dayEntries.length === 1 ? 'entry' : 'entries'}
                  </div>
                )}

                {/* Event Count */}
                {dayEvents.length > 0 && (
                  <div className="text-[10px] text-accent-purple">
                    {dayEvents.length} {dayEvents.length === 1 ? 'event' : 'events'}
                  </div>
                )}

                {/* Task Count */}
                {dayTasks.length > 0 && (
                  <div className="text-[10px] text-accent-blue">
                    {dayTasks.length} {dayTasks.length === 1 ? 'task' : 'tasks'}
                  </div>
                )}
              </div>
            );
          }}
        />
      ) : viewMode === 'weekly' ? (
        /* Weekly View */
        <WeekView
          currentDate={currentDate}
          events={expandedEvents}
          tasks={[]} // No tasks in time tracking context
          onDayClick={handleDayClick}
          onEventClick={handleEventClick}
          showTimeSlots={true}
        />
      ) : viewMode === 'daily' ? (
        /* Daily View */
        <DayView
          date={currentDate}
          events={expandedEvents[getStandardDateKey(currentDate)] || []}
          onEventClick={handleEventClick}
          onTimeSlotClick={() => {
            const dateKey = getStandardDateKey(currentDate);
            handleDayClick(dateKey);
          }}
        />
      ) : (
        /* Agenda/List View */
        <AgendaView
          events={expandedEvents}
          currentDate={currentDate}
          daysToShow={14}
          onEventClick={handleEventClick}
        />
      )}

      {/* Legend */}
      {projects.filter(p => p.active && !p.archived).length > 0 && (
        <div className="bg-surface-light dark:bg-surface-dark rounded-button border border-border-light dark:border-border-dark p-4">
          <h3 className="text-sm font-semibold text-text-light-primary dark:text-text-dark-primary mb-3">
            Project Legend
          </h3>
          <div className="flex flex-wrap gap-3">
            {projects.filter(p => p.active && !p.archived).map(project => (
              <div key={project.id} className="flex items-center gap-2">
                <div
                  className="w-3 h-3 rounded"
                  style={{ backgroundColor: project.color }}
                />
                <span className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
                  {project.name}
                </span>
              </div>
            ))}
            <div className="flex items-center gap-2">
              <div className="w-3 h-3 rounded-buttonbg-gray-400" />
              <span className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
                No Project
              </span>
            </div>
          </div>
        </div>
      )}

      {/* Day Detail Modal */}
      {dayDetailModal && (
        <DayDetailModal
          dateKey={dayDetailModal.dateKey}
          events={dayDetailModal.events}
          tasks={dayDetailModal.tasks}
          timeEntries={dayDetailModal.timeEntries}
          totalDuration={dayDetailModal.totalDuration}
          onClose={() => setDayDetailModal(null)}
          onCreateEvent={() => {
            if (onCreateEvent) {
              onCreateEvent(dayDetailModal.dateKey);
            }
          }}
          onEditEvent={onEditEvent}
          onEditEntry={onEditEntry}
        />
      )}
    </div>
  );
}

import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { Play, Pause, Square, Settings, ChevronUp, ChevronDown, Plus } from 'lucide-react';
import { useTimeTrackingStore } from '../stores/useTimeTrackingStore';
import { useTimeTrackingPanelStore } from '../stores/useTimeTrackingPanelStore';
import { useSettingsStore } from '../stores/useSettingsStore';
import { formatDuration, formatTime } from '../utils/timeFormatters';
import { ProjectSelector } from './ProjectSelector';
import { ManualTimeEntryModal } from './ManualTimeEntryModal';
import { TimeTrackingSettingsModal } from './TimeTrackingSettingsModal';
import type { TimeEntry } from '../types';

/**
 * TimeTrackingPanel Component
 * Persistent timer panel in the sidebar (Toggl-style)
 * Fixed bottom position, shows active timer + recent entries
 */
export function TimeTrackingPanel() {
  const navigate = useNavigate();

  // Global settings (synced app-wide)
  const timeFormat = useSettingsStore((s) => s.timeFormat);

  // Panel-specific settings
  const {
    recentEntriesHeight,
    setRecentEntriesHeight,
    visibleEntries,
    showMiniSummary,
    entryDisplayDensity,
    showSeconds,
    isPanelCollapsed,
    togglePanelCollapsed,
    hasManuallyResized,
    autoExpandEnabled,
    setHasManuallyResized,
  } = useTimeTrackingPanelStore();

  // Time tracking state
  const store = useTimeTrackingStore();
  const {
    activeEntry,
    entries,
    startTimer,
    stopTimer,
    pauseTimer,
    resumeTimer,
    updateTimerDescription,
    getRecentEntries,
    getTodayTotal,
    isTimerRunning,
    timerDescription,
    timerProjectId,
  } = store;

  // Call getter methods
  const isRunning = isTimerRunning();
  const currentDescription = timerDescription();
  const currentProjectId = timerProjectId();

  // Local state
  const [currentTime, setCurrentTime] = useState<number>(0);
  const [recentEntries, setRecentEntries] = useState<TimeEntry[]>([]);
  const [todayTotal, setTodayTotal] = useState<number>(0);
  const [description, setDescription] = useState(currentDescription || '');
  const [selectedProjectId, setSelectedProjectId] = useState<string | null>(currentProjectId || null);
  const [showManualEntryModal, setShowManualEntryModal] = useState(false);
  const [showSettingsModal, setShowSettingsModal] = useState(false);

  // Resize drag state
  const [isDragging, setIsDragging] = useState(false);
  const [dragStartY, setDragStartY] = useState(0);
  const [dragStartHeight, setDragStartHeight] = useState(recentEntriesHeight);

  // Update current time every second when timer is running
  useEffect(() => {
    if (!activeEntry?.startTime) {
      setCurrentTime(0);
      return;
    }

    const updateTime = () => {
      const start = new Date(activeEntry.startTime!).getTime();
      const now = Date.now();
      const elapsed = Math.floor((now - start) / 1000); // seconds
      setCurrentTime(elapsed);
    };

    updateTime(); // Initial update

    // Only set interval if timer is actively running (not paused)
    if (isRunning) {
      const interval = setInterval(updateTime, 1000);
      return () => clearInterval(interval);
    }
  }, [isRunning, activeEntry]);

  // Load recent entries and today's total
  useEffect(() => {
    const loadData = async () => {
      // Get entries from last 48 hours
      const recentEntries = await getRecentEntries(48);
      setRecentEntries(recentEntries.slice(0, visibleEntries)); // Limit to visible count

      // Get today's total
      const total = await getTodayTotal();
      setTodayTotal(total);
    };

    loadData();

    // Refresh every 60 seconds
    const interval = setInterval(loadData, 60000);
    return () => clearInterval(interval);
  }, [entries, visibleEntries, getRecentEntries, getTodayTotal]);

  // Sync description with timer
  useEffect(() => {
    setDescription(currentDescription || '');
  }, [currentDescription]);

  // Auto-expand panel when entries are added (unless user manually resized)
  useEffect(() => {
    // Only auto-expand if feature is enabled and user hasn't manually resized
    if (!autoExpandEnabled || hasManuallyResized) return;

    // Calculate needed height: ~50px per entry, max 400px
    const neededHeight = Math.min(recentEntries.length * 50, 400);

    // Auto-expand to show entries (or collapse to 0 if no entries)
    setRecentEntriesHeight(neededHeight);
  }, [recentEntries.length, autoExpandEnabled, hasManuallyResized, setRecentEntriesHeight]);

  // Handlers
  const handleStartTimer = () => {
    startTimer({
      description: description || 'Untitled Task',
      projectId: selectedProjectId || undefined,
    });
  };

  const handleStopTimer = async () => {
    await stopTimer();
    setDescription(''); // Clear description after stopping
  };

  const handlePauseTimer = () => {
    pauseTimer();
  };

  const handleResumeTimer = () => {
    resumeTimer();
  };

  const handleDescriptionChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const newDescription = e.target.value;
    setDescription(newDescription);
    if (isRunning) {
      updateTimerDescription(newDescription);
    }
  };

  const handleViewAll = () => {
    navigate('/schedule?tab=entries'); // P2 #3 Phase 6B: Navigate to Entries tab instead of Calendar
  };

  const handleContinueEntry = (entry: TimeEntry) => {
    setDescription(entry.description);
    startTimer({
      description: entry.description,
      projectId: entry.projectId,
    });
  };

  // Resize drag handlers
  const handleDragStart = (e: React.MouseEvent) => {
    setIsDragging(true);
    setDragStartY(e.clientY);
    setDragStartHeight(recentEntriesHeight);
    setHasManuallyResized(true); // Lock size at user preference, disable auto-expand
    e.preventDefault();
  };

  // Attach global mouse move and mouseup listeners when dragging
  useEffect(() => {
    if (!isDragging) return;

    const handleDragMove = (e: MouseEvent) => {
      // Calculate the change in Y position (negative because dragging up expands)
      const deltaY = dragStartY - e.clientY;

      // Direct pixel-based calculation: dragging up increases height, dragging down decreases
      const newHeight = dragStartHeight + deltaY;

      // Use store's setter which handles validation (0-400px range)
      setRecentEntriesHeight(newHeight);
    };

    const handleDragEnd = () => {
      setIsDragging(false);
    };

    window.addEventListener('mousemove', handleDragMove);
    window.addEventListener('mouseup', handleDragEnd);

    return () => {
      window.removeEventListener('mousemove', handleDragMove);
      window.removeEventListener('mouseup', handleDragEnd);
    };
  }, [isDragging, dragStartY, dragStartHeight, setRecentEntriesHeight]);

  // Panel container uses auto height - only Recent Entries section is resizable
  const panelStyle = {
    height: 'auto',
  };

  // Get density-based spacing
  const getDensityClasses = () => {
    switch (entryDisplayDensity) {
      case 'compact':
        return 'py-1 text-xs';
      case 'comfortable':
        return 'py-3 text-sm';
      default:
        return 'py-2 text-sm';
    }
  };

  return (
    <div
      className="border-t border-border-light dark:border-border-dark bg-surface-light dark:bg-surface-dark flex flex-col transition-all duration-200"
      style={panelStyle}
    >
      {/* Drag Handle - Only visible when not collapsed */}
      {!isPanelCollapsed && (
        <div
          onMouseDown={handleDragStart}
          className="h-4 cursor-ns-resize hover:bg-accent-magenta/10 dark:hover:bg-accent-cyan/10 transition-all duration-standard ease-smooth flex items-center justify-center group"
          title="Drag to resize panel"
        >
          <div className="w-full h-0.5 bg-border-light dark:bg-border-dark rounded-buttongroup-hover:bg-accent-magenta dark:group-hover:bg-accent-cyan transition-all duration-standard ease-smooth" />
        </div>
      )}

      {/* Panel Header */}
      <div className="flex items-center justify-between px-3 py-0.5 border-b border-border-light dark:border-border-dark">
        <div className="flex items-center gap-2">
          <span className="text-lg">⏱️</span>
          <h3 className="text-sm font-semibold text-text-light-primary dark:text-text-dark-primary">
            Time Tracking
          </h3>
        </div>
        <div className="flex items-center gap-1">
          <button
            onClick={togglePanelCollapsed}
            className="p-1 rounded-buttonhover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated text-text-light-secondary dark:text-text-dark-secondary transition-all duration-standard ease-smooth"
            aria-label={isPanelCollapsed ? 'Expand panel' : 'Collapse panel'}
          >
            {isPanelCollapsed ? (
              <ChevronUp className="w-4 h-4" />
            ) : (
              <ChevronDown className="w-4 h-4" />
            )}
          </button>
          <button
            onClick={() => setShowSettingsModal(true)}
            className="p-1 rounded-buttonhover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated text-text-light-secondary dark:text-text-dark-secondary transition-all duration-standard ease-smooth"
            aria-label="Time tracking settings"
          >
            <Settings className="w-4 h-4" />
          </button>
        </div>
      </div>

      {/* Panel Content (hidden when collapsed) */}
      {!isPanelCollapsed && (
        <>
          {/* Active Timer Section */}
          <div className="px-3 py-3 border-b border-border-light dark:border-border-dark">
            {/* Timer Display - Show whenever there's an active entry */}
            {activeEntry && (
              <div className="mb-2 text-center">
                <div className="text-2xl font-mono font-bold text-accent-magenta dark:text-accent-cyan">
                  {formatDuration(currentTime, { showSeconds })}
                </div>
                {activeEntry.isPaused && (
                  <div className="text-xs text-status-warning font-medium mt-1">
                    Paused
                  </div>
                )}
              </div>
            )}

            {/* Description Input */}
            <input
              type="text"
              value={description}
              onChange={handleDescriptionChange}
              placeholder="What are you working on?"
              className="w-full px-3 py-2 mb-2 text-sm bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-buttonfocus:outline-none focus:ring-2 focus:ring-accent-magenta dark:focus:ring-accent-cyan text-text-light-primary dark:text-text-dark-primary placeholder-text-light-secondary dark:placeholder-text-dark-secondary"
            />

            {/* Project Selector */}
            <div className="mb-3">
              <ProjectSelector
                value={selectedProjectId}
                onChange={setSelectedProjectId}
                placeholder="📁 Select Project"
                showNoProject={true}
              />
            </div>

            {/* Timer Controls */}
            <div className="space-y-2">
              <div className="flex items-center gap-2">
                {!activeEntry ? (
                  <button
                    onClick={handleStartTimer}
                    className="flex-1 flex items-center justify-center gap-2 px-4 py-2 bg-accent-magenta dark:bg-accent-cyan text-white dark:text-dark-background rounded-buttonfont-medium hover:opacity-90 transition-opacity"
                  >
                    <Play className="w-4 h-4" />
                    Start Timer
                  </button>
                ) : (
                <>
                  <button
                    onClick={activeEntry?.isPaused ? handleResumeTimer : handlePauseTimer}
                    className="flex-1 flex items-center justify-center gap-2 px-4 py-2 bg-status-warning text-white rounded-buttonfont-medium hover:opacity-90 transition-opacity"
                  >
                    {activeEntry?.isPaused ? (
                      <>
                        <Play className="w-4 h-4" />
                        Resume
                      </>
                    ) : (
                      <>
                        <Pause className="w-4 h-4" />
                        Pause
                      </>
                    )}
                  </button>
                  <button
                    onClick={handleStopTimer}
                    className="flex-1 flex items-center justify-center gap-2 px-4 py-2 bg-status-error text-white rounded-buttonfont-medium hover:opacity-90 transition-opacity"
                  >
                    <Square className="w-4 h-4" />
                    Stop
                  </button>
                </>
              )}
              </div>

              {/* Manual Entry Button */}
              <button
                onClick={() => setShowManualEntryModal(true)}
                className="w-full flex items-center justify-center gap-2 px-3 py-1.5 text-sm bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-buttontext-text-light-primary dark:text-text-dark-primary font-medium hover:bg-surface-light dark:hover:bg-neutral-800 transition-all duration-standard ease-smooth"
              >
                <Plus className="w-4 h-4" />
                Add Manual Entry
              </button>
            </div>
          </div>

          {/* Recent Entries List */}
          {recentEntriesHeight > 0 && (
            <div
              className="overflow-hidden px-3 py-2 transition-all duration-100"
              style={{ height: `${recentEntriesHeight}px` }}
            >
              <h4 className="text-xs font-semibold text-text-light-secondary dark:text-text-dark-secondary mb-2">
                Recent Entries (Last 48h)
              </h4>
              <div className="overflow-y-auto" style={{ height: `calc(100% - 24px)` }}>
                {recentEntries.length === 0 ? (
                  <p className="text-xs text-text-light-tertiary dark:text-text-dark-tertiary italic">
                    No entries yet. Start your first timer!
                  </p>
                ) : (
                  <div className="space-y-1">
                    {recentEntries.map((entry) => (
                      <div
                        key={entry.id}
                        className={`${getDensityClasses()} px-2 rounded-buttonhover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated cursor-pointer transition-all duration-standard ease-smooth`}
                        onClick={() => handleContinueEntry(entry)}
                      >
                        <div className="flex items-start justify-between">
                          <div className="flex-1 min-w-0">
                            <p className="text-text-light-primary dark:text-text-dark-primary truncate font-medium">
                              {entry.description}
                            </p>
                            <div className="flex items-center gap-2 text-xs text-text-light-secondary dark:text-text-dark-secondary">
                              <span>
                                {formatTime(new Date(entry.startTime), timeFormat)}
                              </span>
                              {entry.endTime && (
                                <>
                                  <span>-</span>
                                  <span>
                                    {formatTime(new Date(entry.endTime), timeFormat)}
                                  </span>
                                </>
                              )}
                              <span className="font-medium">
                                ({formatDuration(entry.duration, { showSeconds: false })})
                              </span>
                            </div>
                          </div>
                        </div>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            </div>
          )}

          {/* Mini Summary & View All Button */}
          {showMiniSummary && (
            <div className="px-3 py-3 border-t border-border-light dark:border-border-dark">
              <div className="flex items-center justify-between mb-2">
                <span className="text-xs font-semibold text-text-light-secondary dark:text-text-dark-secondary">
                  Today's Total:
                </span>
                <span className="text-sm font-mono font-bold text-accent-magenta dark:text-accent-cyan">
                  {formatDuration(todayTotal, { showSeconds: false })}
                </span>
              </div>
              <button
                onClick={handleViewAll}
                className="w-full px-3 py-2 text-sm bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-buttonhover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated text-text-light-primary dark:text-text-dark-primary font-medium transition-all duration-standard ease-smooth"
              >
                View All →
              </button>
            </div>
          )}
        </>
      )}

      {/* Manual Entry Modal */}
      {showManualEntryModal && (
        <ManualTimeEntryModal
          onClose={async () => {
            setShowManualEntryModal(false);
            // Refresh recent entries after adding manual entry
            const recentEntries = await getRecentEntries(48);
            setRecentEntries(recentEntries.slice(0, visibleEntries));
            const total = await getTodayTotal();
            setTodayTotal(total);
          }}
        />
      )}

      {/* Settings Modal */}
      <TimeTrackingSettingsModal
        isOpen={showSettingsModal}
        onClose={() => setShowSettingsModal(false)}
      />
    </div>
  );
}
